// ============================================================
// WF-05: HANDOFF TELEGRAM
// Recibe mensajes de la secretaria en Telegram y los reenvía
// al paciente por WhatsApp
// ============================================================

const helpers = this.helpers;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const WA_TOKEN = $env.META_WHATSAPP_TOKEN;
const PHONE_ID = '963190063548521';
const TELEGRAM_TOKEN = $env.TELEGRAM_BOT_TOKEN || '';

async function supaGet(t, p) { try { return await helpers.httpRequest({ method:'GET', url:`${SUPABASE_URL}/rest/v1/${t}`, qs:p||{}, headers:{'apikey':SUPABASE_KEY,'Authorization':`Bearer ${SUPABASE_KEY}`} }); } catch(e) { return []; } }
async function supaUpdate(t, f, d) { try { await helpers.httpRequest({ method:'PATCH', url:`${SUPABASE_URL}/rest/v1/${t}`, qs:f, headers:{'apikey':SUPABASE_KEY,'Authorization':`Bearer ${SUPABASE_KEY}`,'Content-Type':'application/json'}, body:JSON.stringify({...d,updated_at:new Date().toISOString()}) }); } catch(e) {} }
async function sendWA(ph, tx) { try { await helpers.httpRequest({ method:'POST', url:`https://graph.facebook.com/v21.0/${PHONE_ID}/messages`, headers:{'Authorization':`Bearer ${WA_TOKEN}`,'Content-Type':'application/json'}, body:JSON.stringify({messaging_product:'whatsapp',to:ph,type:'text',text:{body:tx}}) }); } catch(e) {} }
async function sendTG(chatId, tx) { try { await helpers.httpRequest({ method:'POST', url:`https://api.telegram.org/bot${TELEGRAM_TOKEN}/sendMessage`, headers:{'Content-Type':'application/json'}, body:JSON.stringify({chat_id:chatId,text:tx,parse_mode:'HTML'}) }); } catch(e) {} }

const msg = $input.first().json;
const text = msg?.message?.text || '';
const chatId = msg?.message?.chat?.id || '';
const replyTo = msg?.message?.reply_to_message?.text || '';

if (!text || !chatId) return [{ json: { action: 'no_message' } }];

// === COMANDO /fin === Cerrar handoff
if (text.trim().toLowerCase() === '/fin') {
  // Buscar conversacion en handoff
  const convs = await supaGet('consultorio_conversaciones', { handoff_humano: 'eq.true', select: '*' });
  if (!convs?.length) {
    await sendTG(chatId, 'No hay conversaciones de handoff activas.');
    return [{ json: { action: 'no_active_handoff' } }];
  }
  // Si hay una sola, cerrarla. Si hay varias, cerrar la más reciente.
  const conv = convs.sort((a,b) => new Date(b.updated_at) - new Date(a.updated_at))[0];
  await supaUpdate('consultorio_conversaciones', { id: `eq.${conv.id}` }, { handoff_humano: false, estado: 'inicio', contexto: {} });
  await sendWA(conv.telefono_wa, 'Recepción finalizó la conversación. Si necesitás algo más, escribime. \ud83d\udc4b');
  await sendTG(chatId, `\u2705 Handoff cerrado con ${conv.contexto?.pacienteNombre || conv.telefono_wa}.`);
  return [{ json: { action: 'handoff_closed', phone: conv.telefono_wa } }];
}

// === RESPUESTA A PACIENTE === Reenviar por WhatsApp
// Buscar conversacion activa en handoff
const convs = await supaGet('consultorio_conversaciones', { handoff_humano: 'eq.true', select: '*' });
if (!convs?.length) {
  await sendTG(chatId, 'No hay pacientes en handoff. Los mensajes no se reenv\u00edan.');
  return [{ json: { action: 'no_handoff_active' } }];
}

// Si hay una sola conversación en handoff, enviar ahí
// Si hay varias, usar la más reciente (en produccion se usaría reply threading)
const conv = convs.sort((a,b) => new Date(b.updated_at) - new Date(a.updated_at))[0];

await sendWA(conv.telefono_wa, text);
await supaUpdate('consultorio_conversaciones', { id: `eq.${conv.id}` }, { updated_at: new Date().toISOString() });
await sendTG(chatId, `\u2705 Mensaje enviado a ${conv.contexto?.pacienteNombre || 'paciente'}.`);

return [{ json: { action: 'message_forwarded', phone: conv.telefono_wa, message: text } }];

